using UnityEngine;

public class Player : MonoBehaviour
{
    public int Health = 100;
    public int Currency = 1000;

    public void TakeDamage(int damage)
    {
        Health -= damage;

        if (Health <= 0)
        {
            // You can add a game over logic here
            Debug.Log("Game Over");
        }
    }

    public void PurchaseItem(int cost)
    {
